import React, { useState, useEffect } from 'react';
import { User } from 'firebase/auth'; // Keep type for compatibility
import { View, UserProfile, GamificationProfile } from './types';
import { views } from './constants';
import { mockTrainer, mockUsers, addUser, updateUserPlan, cleanOldTrackers, completeUserProfile, checkAndApplyBirthdayBonus, updateUserProfile as updateUserProfileService } from './services/mockData';

import NavMenu from './components/NavMenu';
import HomeView from './components/views/HomeView';
import PlansView from './components/views/PlansView';
import AgendaView from './components/views/AgendaView';
import AchievementsView from './components/views/AchievementsView';
import LoginView from './components/views/LoginView';
import TrainerDashboardView from './components/views/TrainerDashboardView';
import DashboardView from './components/views/DashboardView';
import ChatView from './components/ChatView';
import RewardNotification from './components/RewardNotification';
import RewardsStoreView from './components/views/RewardsStoreView';
import ProfileView from './components/views/ProfileView';
import { MessageCircle, LogOut, AlertTriangle } from 'lucide-react';

const createDefaultGamificationProfile = (userId: string): GamificationProfile => ({
    userId: userId,
    totalPoints: 0,
    level: 1,
    experience: 0,
    experienceToNextLevel: 100, // Points for level 2
    badges: [],
    achievements: [],
    streaks: [
        { type: 'training', current: 0, best: 0, lastUpdate: { toDate: () => new Date(0) } as any }
    ],
});

// Main App Component
const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(views.HOME);
  const [isLoggedIn, setIsLoggedIn] = useState<boolean>(false);
  const [isTrainer, setIsTrainer] = useState<boolean>(false);
  const [user, setUser] = useState<(UserProfile & { id: string }) | null>(null);
  const [chatCompanionId, setChatCompanionId] = useState<string | null>(null);
  const [showChat, setShowChat] = useState<boolean>(false);
  const [selectedPlan, setSelectedPlan] = useState<string | null>(null);
  const [rewardQueue, setRewardQueue] = useState<any[]>([]);
  const [currentNotification, setCurrentNotification] = useState<any>(null);
  const [pendingCompletionUser, setPendingCompletionUser] = useState<(UserProfile & { id: string }) | null>(null);

  // Logout Modal State
  const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);

  const trainerId = mockTrainer.id;

  useEffect(() => {
    cleanOldTrackers();
  }, []);

  useEffect(() => {
    if (rewardQueue.length > 0 && !currentNotification) {
      const nextReward = rewardQueue[0];
      setCurrentNotification(nextReward);
      setRewardQueue(q => q.slice(1));
    }
  }, [rewardQueue, currentNotification]);

  const handleLogin = ({ usernameOrEmail, password }: { usernameOrEmail: string, password: string }) => {
    // Case insensitive username/email check
    const inputLogin = usernameOrEmail.toLowerCase().trim();

    const foundUser = mockUsers.find(u => 
        u.email.toLowerCase() === inputLogin || 
        u.username.toLowerCase() === inputLogin
    );

    // Password remains case-sensitive
    if (foundUser && foundUser.password === password) {
        if (!foundUser.registrationCompleted) {
            setPendingCompletionUser(foundUser);
            setCurrentView(views.LOGIN); 
            return; 
        }
        setUser(foundUser);
        setIsLoggedIn(true);
        setIsTrainer(foundUser.isTrainer);
        setCurrentView(views.DASHBOARD);
        const birthdayRewards = checkAndApplyBirthdayBonus(foundUser.id);
        if (birthdayRewards) {
            setRewardQueue(q => [...q, birthdayRewards]);
        }
    } else {
        throw new Error("Credenciales inválidas.");
    }
  };

  const handleRegister = ({ email, password }: { email: string, password: string }): UserProfile & { id: string } => {
      const existingUser = mockUsers.find(u => u.email.toLowerCase() === email.toLowerCase());
      if (existingUser) {
          throw new Error("El email ya está registrado. Por favor, inicia sesión.");
      }

      const newUserId = `client${Date.now()}`;
      const newUser: UserProfile & { id: string } = {
          id: newUserId,
          email: email,
          username: email.split('@')[0],
          displayName: email.split('@')[0],
          password: password,
          plan: selectedPlan || undefined,
          isTrainer: false,
          createdAt: { toDate: () => new Date() } as any,
          gamification: createDefaultGamificationProfile(newUserId),
          registrationCompleted: false,
      };

      addUser(newUser);
      setSelectedPlan(null);
      return newUser;
  };

  const completeRegistration = (userToComplete: UserProfile & { id: string }, additionalData: { displayName: string; birthDate: string }) => {
      completeUserProfile(userToComplete.id, additionalData);
      const updatedUser = mockUsers.find(u => u.id === userToComplete.id);
      if (updatedUser) {
          setUser(updatedUser);
          setIsLoggedIn(true);
          setIsTrainer(false);
          setCurrentView(views.DASHBOARD);
          setPendingCompletionUser(null);
          alert(`¡Bienvenido a TommyBox, ${additionalData.displayName}! 🎉`);
      }
  };

  // Trigger the logout confirmation modal
  const requestLogout = () => {
      setShowLogoutConfirm(true);
  };

  // Actual Logout Logic
  const executeLogout = () => {
    setShowLogoutConfirm(false);
    // Aggressive reset of all states
    setChatCompanionId(null);
    setShowChat(false);
    setPendingCompletionUser(null);
    setUser(null);
    setIsTrainer(false);
    setIsLoggedIn(false);
    setCurrentView(views.HOME);

    // Optional: clear any ephemeral states if necessary
    window.scrollTo(0, 0);
  };

  const handleOpenChat = () => {
      if (isTrainer && selectedClientForChat) {
          setChatCompanionId(selectedClientForChat);
          setShowChat(true);
      } else if (!isTrainer && trainerId) {
          setChatCompanionId(trainerId);
          setShowChat(true);
      }
  };

  const handlePlanSelect = (planName: string) => {
    if (isLoggedIn && user) {
        updateUserPlan(user.id, planName);
        setUser({ ...user, plan: { ...user.plan, name: planName } as any });
        alert(`¡Plan "${planName}" seleccionado!`);
        setCurrentView(views.DASHBOARD);
    } else {
        setSelectedPlan(planName);
        setCurrentView(views.LOGIN);
    }
  };

  const handleUpdateProfile = (updatedData: Partial<UserProfile>) => {
    if (!user) return;
    const updatedUser = updateUserProfileService(user.id, updatedData);
    if (updatedUser) {
        setUser(updatedUser);
        alert("Perfil actualizado con éxito.");
        setCurrentView(views.DASHBOARD);
    } else {
        alert("Error al actualizar el perfil.");
    }
  };

  const [selectedClientForChat, setSelectedClientForChat] = useState<string|null>(null);

  const renderView = () => {
    switch (currentView) {
      case views.HOME:
        return <HomeView setCurrentView={setCurrentView} />;
      case views.PLANS:
        return <PlansView setCurrentView={setCurrentView} isLoggedIn={isLoggedIn} handlePlanSelect={handlePlanSelect} isTrainer={isTrainer} />;
      case views.AGENDA:
        return <AgendaView userId={user?.id} userPlan={user?.plan} setRewardQueue={setRewardQueue} setCurrentView={setCurrentView} isTrainer={isTrainer} />;
      case views.ACHIEVEMENTS:
        return <AchievementsView />;
      case views.LOGIN:
        return <LoginView setCurrentView={setCurrentView} isLoggedIn={isLoggedIn} handleLogin={handleLogin} handleRegister={handleRegister} completeRegistration={completeRegistration} pendingCompletionUser={pendingCompletionUser} setPendingCompletionUser={setPendingCompletionUser} />;
      case views.REWARDS_STORE:
        if (!isLoggedIn || !user) return <LoginView setCurrentView={setCurrentView} isLoggedIn={isLoggedIn} handleLogin={handleLogin} handleRegister={handleRegister} completeRegistration={completeRegistration} pendingCompletionUser={pendingCompletionUser} setPendingCompletionUser={setPendingCompletionUser} />;
        return <RewardsStoreView user={user} setCurrentView={setCurrentView} />;
      case views.PROFILE:
        if (!isLoggedIn || !user) return <LoginView setCurrentView={setCurrentView} isLoggedIn={isLoggedIn} handleLogin={handleLogin} handleRegister={handleRegister} completeRegistration={completeRegistration} pendingCompletionUser={pendingCompletionUser} setPendingCompletionUser={setPendingCompletionUser} />;
        return <ProfileView user={user} onUpdateProfile={handleUpdateProfile} setCurrentView={setCurrentView} />;
      case views.DASHBOARD:
        if (!isLoggedIn || !user) return <LoginView setCurrentView={setCurrentView} isLoggedIn={isLoggedIn} handleLogin={handleLogin} handleRegister={handleRegister} completeRegistration={completeRegistration} pendingCompletionUser={pendingCompletionUser} setPendingCompletionUser={setPendingCompletionUser} />;
        if (isTrainer) {
          return <TrainerDashboardView setChatCompanionId={setChatCompanionId} setShowChat={setShowChat} setSelectedClientForChat={setSelectedClientForChat} handleLogout={requestLogout} />;
        }
        const userAsFirebaseUser = { uid: user.id, email: user.email } as User;
        return <DashboardView trainerId={trainerId} user={userAsFirebaseUser} setChatCompanionId={setChatCompanionId} setShowChat={setShowChat} setCurrentView={setCurrentView} setRewardQueue={setRewardQueue} />;
      default:
        return <HomeView setCurrentView={setCurrentView} />;
    }
  };

  return (
    <div className="flex flex-col min-h-screen bg-gray-50 font-sans text-gray-900 antialiased">
      {/* Global Transition Styles */}
      <style>{`
        @keyframes pageFadeIn {
          0% { opacity: 0; transform: translateY(10px); }
          100% { opacity: 1; transform: translateY(0); }
        }
        .page-transition {
          animation: pageFadeIn 0.4s cubic-bezier(0.16, 1, 0.3, 1) forwards;
        }
      `}</style>

      {/* Header Fixed - Updated Height */}
      <header className="fixed top-0 left-0 right-0 z-[50] bg-white/95 backdrop-blur-md shadow-sm border-b border-gray-100 h-20 sm:h-24 transition-all duration-300">
        <NavMenu currentView={currentView} setCurrentView={setCurrentView} isLoggedIn={isLoggedIn} handleLogout={requestLogout} />
      </header>

      {/* Main Content with Top Padding compensation - Added Animation Key */}
      <main className="flex-1 pt-20 sm:pt-24 overflow-x-hidden relative">
        <div key={currentView} className="page-transition h-full">
            {renderView()}
        </div>
      </main>

      {/* Notification Toast */}
      {currentNotification && (
        <RewardNotification
            reward={currentNotification}
            onDismiss={() => setCurrentNotification(null)}
        />
      )}

      {/* Custom Logout Modal */}
      {showLogoutConfirm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in">
            <div className="bg-white rounded-2xl p-8 max-w-sm w-full mx-auto shadow-2xl text-center transform scale-100 animate-scale-up">
                <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4 text-red-500">
                    <LogOut size={32} />
                </div>
                <h3 className="text-2xl font-bold text-gray-900 mb-2">¿Cerrar Sesión?</h3>
                <p className="text-gray-600 mb-8">¿Estás seguro que deseas salir de tu cuenta?</p>
                <div className="flex gap-4">
                    <button 
                        onClick={() => setShowLogoutConfirm(false)}
                        className="flex-1 py-3 px-4 bg-gray-100 text-gray-700 font-bold rounded-xl hover:bg-gray-200 transition-colors"
                    >
                        Cancelar
                    </button>
                    <button 
                        onClick={executeLogout}
                        className="flex-1 py-3 px-4 bg-red-600 text-white font-bold rounded-xl hover:bg-red-700 transition-colors shadow-lg shadow-red-200"
                    >
                        Sí, Salir
                    </button>
                </div>
            </div>
        </div>
      )}

      {/* Floating Chat Button (Client Only typically, or global) */}
      {isLoggedIn && !showChat && (
        <div className="fixed bottom-24 right-5 z-[40]">
          <button
            onClick={handleOpenChat}
            className="w-14 h-14 bg-gradient-to-r from-blue-600 to-blue-700 text-white rounded-full flex items-center justify-center shadow-lg shadow-blue-500/30 transition-transform duration-300 hover:scale-110 active:scale-95"
            aria-label="Chat"
          >
            <MessageCircle size={26} fill="currentColor" className="text-white" />
          </button>
        </div>
      )}

      {/* Chat Overlay */}
      {showChat && user && chatCompanionId && (
          <ChatView
              userId={user.id}
              companionId={chatCompanionId}
              onClose={() => setShowChat(false)}
          />
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { Home, Handshake, Calendar, Award, User, Gift, LogOut } from 'lucide-react';
import { View } from '../types';
import { views } from '../constants';

interface NavMenuProps {
  currentView: View;
  setCurrentView: (view: View) => void;
  isLoggedIn: boolean;
  handleLogout?: () => void;
}

const NavMenu: React.FC<NavMenuProps> = ({ currentView, setCurrentView, isLoggedIn, handleLogout }) => {
  const navItems = [
    { id: 'home', label: 'Inicio', icon: Home, view: views.HOME },
    { id: 'plans', label: 'Planes', icon: Handshake, view: views.PLANS },
    { id: 'agenda', label: 'Agenda', icon: Calendar, view: views.AGENDA },
    { id: 'achievements', label: 'Comunidad', icon: Award, view: views.ACHIEVEMENTS },
    { id: 'login', label: 'Login', icon: User, view: views.LOGIN },
  ];

  const loggedInItems = [
    { id: 'dashboard', label: 'Panel', icon: User, view: views.DASHBOARD },
    { id: 'agenda', label: 'Agenda', icon: Calendar, view: views.AGENDA },
    { id: 'rewards-store', label: 'Tienda', icon: Gift, view: views.REWARDS_STORE },
    { id: 'achievements', label: 'Social', icon: Award, view: views.ACHIEVEMENTS },
    { id: 'logout', label: 'Salir', icon: LogOut, action: true }, 
  ];

  const displayedItems = isLoggedIn ? loggedInItems : navItems;
  const numItems = displayedItems.length;

  // Logic for the floating indicator calculation
  const currentIndex = displayedItems.findIndex(item => 'view' in item && item.view === currentView);
  // Default to 0 if not found, but hide it if it's logout (action)
  const activeIndex = currentIndex === -1 ? 0 : currentIndex;

  // Calculate percentage for left position
  const indicatorWidthPercent = 100 / numItems;
  const indicatorLeftPercent = activeIndex * indicatorWidthPercent;

  const handleItemClick = (e: React.MouseEvent, item: any) => {
      // Haptic Visual Feedback
      const btn = e.currentTarget as HTMLDivElement;
      btn.classList.add('scale-90');
      setTimeout(() => btn.classList.remove('scale-90'), 150);

      if (item.action && item.id === 'logout') {
          if (handleLogout) {
             handleLogout();
          }
      } else if (item.view) {
          setCurrentView(item.view);
      }
  };

  return (
    <nav className="container mx-auto h-full px-4 sm:px-6">
        {/* Constrain width to add whitespace on desktop */}
        <div className="relative h-full flex items-center justify-between max-w-2xl mx-auto">

          {displayedItems.map((item) => {
            const isLogout = item.id === 'logout';
            const isActive = !item.action && currentView === item.view;

            // Dynamic styling
            let iconClass = 'text-gray-400';
            let labelClass = 'text-gray-400 font-medium';
            let containerClass = 'hover:bg-gray-50';

            if (isLogout) {
                iconClass = 'text-red-500';
                labelClass = 'text-red-500 font-bold';
                containerClass = 'hover:bg-red-50';
            } else if (isActive) {
                iconClass = 'text-blue-600';
                labelClass = 'text-blue-600 font-bold';
            } else {
                iconClass = 'text-gray-400 group-hover:text-gray-600';
            }

            return (
                <div
                  key={item.id}
                  onClick={(e) => handleItemClick(e, item)}
                  className={`flex-1 flex flex-col items-center justify-center cursor-pointer select-none transition-all duration-200 active:scale-95 group rounded-xl py-2 ${containerClass}`}
                >
                  <div className={`
                    flex items-center justify-center 
                    w-12 h-12 mb-1 rounded-2xl transition-all duration-300
                    ${isActive ? 'bg-blue-50 scale-110 shadow-sm' : 'bg-transparent'}
                  `}>
                    <item.icon size={22} className={`transition-colors duration-300 ${iconClass}`} strokeWidth={isActive ? 2.5 : 2} />
                  </div>
                  <span className={`text-[10px] sm:text-xs tracking-wide transition-colors duration-300 ${labelClass}`}>
                    {item.label}
                  </span>
                </div>
            );
          })}

          {/* Refined Active Indicator (Bottom Line) */}
          <div className="absolute bottom-0 left-0 w-full h-[3px] bg-gray-100/50 rounded-full overflow-hidden pointer-events-none">
             {currentIndex !== -1 && (
                <div
                  className="h-full bg-blue-600 rounded-full transition-all duration-500 cubic-bezier(0.4, 0, 0.2, 1) shadow-[0_0_10px_rgba(37,99,235,0.5)]"
                  style={{ 
                      width: `${indicatorWidthPercent * 0.4}%`, // Only 40% of the slot width
                      marginLeft: `${indicatorLeftPercent + (indicatorWidthPercent * 0.3)}%` // Centered in the slot
                  }}
                ></div>
             )}
          </div>

        </div>
    </nav>
  );
};

export default NavMenu;

import React, { useState, useEffect } from 'react';
import { Gift, ShoppingBag, Award, Check, AlertCircle, X, Sparkles, Zap, ChevronRight, Lock } from 'lucide-react';
import { View, RewardItem, UserProfile } from '../../types';
import { REWARD_CATALOG, getAvailableStock, redeemReward, getUserRedemptions } from '../../services/mockData';

interface RewardsStoreViewProps {
  user: UserProfile & { id: string };
  setCurrentView: (view: View) => void;
}

const RewardsStoreView: React.FC<RewardsStoreViewProps> = ({ user, setCurrentView }) => {
  const [selectedCategory, setSelectedCategory] = useState<string>('all');
  const [showRedeemModal, setShowRedeemModal] = useState(false);
  const [selectedReward, setSelectedReward] = useState<RewardItem | null>(null);
  const [redemptionResult, setRedemptionResult] = useState<{ success: boolean; message: string } | null>(null);
  const [currentUser, setCurrentUser] = useState(user);
  const [activeTab, setActiveTab] = useState<'catalog' | 'history'>('catalog');

  const userPoints = currentUser?.gamification?.totalPoints || 0;
  const userRedemptions = getUserRedemptions(currentUser?.id || '');

  const categories = [
    { id: 'all', label: 'Todos' },
    { id: 'merch', label: 'Equipamiento' },
    { id: 'subscription', label: 'Membresía' },
    { id: 'exclusive', label: 'Exclusivo' }
  ];

  const filteredRewards = selectedCategory === 'all'
    ? REWARD_CATALOG
    : REWARD_CATALOG.filter(r => r.category === selectedCategory);

  const handleRedeem = () => {
    if (!selectedReward) return;

    const result = redeemReward(currentUser.id, selectedReward.id);
    setRedemptionResult(result);

    if (result.success) {
      setCurrentUser(prev => ({
          ...prev!,
          gamification: {
              ...prev!.gamification,
              totalPoints: prev!.gamification.totalPoints - selectedReward.pointsCost
          }
      }));
      setTimeout(() => {
        setShowRedeemModal(false);
        setRedemptionResult(null);
        setSelectedReward(null);
      }, 3000);
    }
  };

  const openModal = (reward: RewardItem) => {
    setSelectedReward(reward);
    setShowRedeemModal(true);
  };

  const closeModal = () => {
    setShowRedeemModal(false);
    setRedemptionResult(null);
    setSelectedReward(null);
  };

  return (
    <div className="max-w-7xl mx-auto p-4 md:p-8 min-h-screen bg-gray-50/50">

      {/* Premium Header Card */}
      <div className="relative overflow-hidden rounded-3xl bg-gray-900 text-white shadow-2xl mb-10 transform transition-transform hover:scale-[1.01] duration-500">
