            {!redemptionResult ? (
              <>
                <div className="text-center mb-6">
                    <div className="w-24 h-24 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-4 text-6xl">
                        {selectedReward.icon}
                    </div>
                    <p className="text-xs font-bold text-blue-600 uppercase tracking-widest mb-2">Confirmar Canje</p>
                    <h3 className="text-2xl font-black text-gray-900 leading-tight mb-2">{selectedReward.name}</h3>
                    <p className="text-sm text-gray-500">{selectedReward.description}</p>
                </div>

                <div className="bg-gray-50 rounded-xl p-4 mb-6 border border-gray-100">
                    <div className="flex justify-between items-center mb-2">
                        <span className="text-sm font-medium text-gray-600">Costo</span>
                        <span className="font-bold text-red-500">-{selectedReward.pointsCost} pts</span>
                    </div>
                    <div className="flex justify-between items-center pt-2 border-t border-gray-200">
                        <span className="text-sm font-medium text-gray-600">Saldo Final</span>
                        <span className="font-bold text-gray-900">{userPoints - selectedReward.pointsCost} pts</span>
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-3">
                    <button onClick={closeModal} className="py-3 bg-white border border-gray-200 text-gray-700 rounded-xl font-bold hover:bg-gray-50 transition-colors">Cancelar</button>
                    <button onClick={handleRedeem} className="py-3 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-colors shadow-lg shadow-blue-200">Confirmar</button>
                </div>
              </>
            ) : (
              <div className="text-center py-4">
                {redemptionResult.success ? (
                  <>
                    <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-6 animate-scale-up">
                        <Check className="text-green-600" size={40} strokeWidth={3} />
                    </div>
                    <h3 className="text-2xl font-black text-gray-900 mb-2">¡Disfrútalo!</h3>
                    <p className="text-gray-600 mb-4">{redemptionResult.message}</p>
                  </>
